use strict;
use warnings;
use PDF::API2;
use Text::CSV;

# Function to extract metadata from PDF
sub extract_metadata {
    my ($file) = @_;
    my $pdf = PDF::API2->open($file);

    # Extract metadata
    my $info = $pdf->info;
    my $author = $info->author;
    my $title = $info->title;
    my $creation_date = $info->creation;

    return ($author, $title, $creation_date);
}

# Function to extract table content from PDF
sub extract_table {
    my ($file, $page_num, $start_x, $start_y, $end_x, $end_y) = @_;
    my $pdf = PDF::API2->open($file);

    # Extract text from the specified region
    my $page = $pdf->page($page_num);
    my $text = $page->text_layer->text;

    # Filter text within the specified region
    my $filtered_text = $text->extract_rect($start_x, $start_y, $end_x, $end_y);

    # Parse the extracted text using Text::CSV (assuming table data is in CSV format)
    my $csv = Text::CSV->new();
    my @table_data;

    foreach my $line (@$filtered_text) {
        if ($csv->parse($line)) {
            push @table_data, $csv->fields();
        }
    }

    return \@table_data;
}

# Main script
